#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    for (int tc = 0; tc < T; ++tc) {
        char numStr[32], denStr[32];
        if (scanf("%31s %31s", numStr, denStr) != 2) break;
        char *endptr;
        long num = strtol(numStr, &endptr, 10);
        int numOk = (*endptr == '\0');
        long den = strtol(denStr, &endptr, 10);
        int denOk = (*endptr == '\0');
        if (!numOk || !denOk) {
            printf("Invalid number format\n");
        } else if (den == 0) {
            printf("Cannot divide by zero\n");
        } else {
            printf("Result: %ld\n", num / den);
        }
        printf("Execution Completed\n");
    }
    return 0;
}

