#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out = []
    for _ in range(t):
        if idx + 1 >= len(data):
            break
        num_str = data[idx]
        den_str = data[idx + 1]
        idx += 2
        try:
            num = int(num_str)
            den = int(den_str)
            if den == 0:
                raise ZeroDivisionError("Cannot divide by zero")
            out.append(f"Result: {num // den}")
        except ValueError:
            out.append("Invalid number format")
        except ZeroDivisionError as e:
            out.append(str(e))
        except Exception:
            out.append("Some other exception occurred")
        finally:
            out.append("Execution Completed")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

